import UIKit
import LocalAuthentication

class BiometricAuth {
    static func authenticate() {
        // Get context from current user
        let context = LAContext()
        
        // Set reason for authentication
        var error: NSError?
        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            let reason = "Please authenticate with your face or touch ID"
            
            // Present biometric prompt
            let prompt = LAContext.AuthenticationReason(reason: reason)
            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, evaluateError in
                if success {
                    // Authentication succeeded
                    print("User authenticated successfully")
                    
                    // Store flag indicating user is authenticated
                    UserDefaults.standard.set(true, forKey: "isAuthenticated")
                } else {
                    // Authentication failed
                    print("Authentication failed: \(evaluateError?.localizedDescription ?? "Unknown error")")
                }
            }
        } else {
            // Biometric authentication is not available or disabled by user
            print("Biometric authentication not available or disabled by user")
        }
    }
}